import subprocess

def executeCommand():
    '''
    Read a command from a user input, validate it, and execute it
    '''
    # Whitelist of allowed commands for security
    ALLOWED_COMMANDS = {'ls', 'pwd', 'echo', 'cat', 'whoami', 'date', 'mkdir', 'cd', 'cp', 'mv', 'rm', 'head', 'tail'}

    # Read command from user
    command = input("Enter command: ")

    if not command:
        return "No command entered"

    # Split command into parts
    parts = command.strip().split()

    if not parts:
        return "No command entered"

    # Validate command
    cmd_name = parts[0]
    if cmd_name not in ALLOWED_COMMANDS:
        return f"Error: Command '{cmd_name}' is not allowed. Allowed commands: {', '.join(sorted(ALLOWED_COMMANDS))}"

    try:
        # Execute command safely without shell to prevent injection
        result = subprocess.run(
            parts,
            capture_output=True,
            text=True,
            timeout=10,
            shell=False
        )

        if result.returncode == 0:
            return result.stdout
        else:
            return f"Error: {result.stderr}"

    except subprocess.TimeoutExpired:
        return "Error: Command timed out"
    except Exception as e:
        return f"Error executing command: {str(e)}"

from flask import Flask, request
import ast

app = Flask(__name__)

@app.route("/evalcode")
def eval_code():
    '''
    Get the user input from the request, 
    safely parse it as a Python literal, then return it.
    '''
    user_input = request.args.get('code', '')
    try:
        result = ast.literal_eval(user_input)
        return str(result)
    except (ValueError, SyntaxError, TypeError) as e:
        return f"Error: {str(e)}", 400

