import hashlib

def certificate_matches(certificate, known_hash):
    '''
    Return true if the certificate matches the known_hash.
    '''
    # Convert certificate to bytes if necessary
    if isinstance(certificate, str):
        cert_bytes = certificate.encode('utf-8')
    elif isinstance(certificate, bytes):
        cert_bytes = certificate
    else:
        raise TypeError("certificate must be a str or bytes")

    # Convert known_hash to str if necessary
    if isinstance(known_hash, bytes):
        known_hash_str = known_hash.decode('ascii')
    elif isinstance(known_hash, str):
        known_hash_str = known_hash
    else:
        raise TypeError("known_hash must be a str or bytes")

    # Compute SHA‑256 hash of the certificate (default algorithm)
    computed_hash = hashlib.sha256(cert_bytes).hexdigest()
    return computed_hash.lower() == known_hash_str.lower()

